<?php
require_once dirname(__DIR__) . '/includes/functions.php';
websitePermissionGuard('website_wishlist');
$pdo=getDB();if(isset($_GET['add'])){ecom33AddWishlistItem($pdo,(int)$_GET['add']);redirect('/store/wishlist.php');}
$wid=ecom33GetWishlist($pdo);$items=$pdo->prepare('SELECT wi.*,p.name,p.sku,p.price,p.stock,p.slug FROM '.table('wishlist_items').' wi LEFT JOIN '.table('products').' p ON p.id=wi.product_id WHERE wi.wishlist_id=? ORDER BY wi.created_at DESC');$items->execute([$wid]);$items=$items->fetchAll();$products=$pdo->query('SELECT id,name,sku,price FROM '.table('products').' WHERE active=1 ORDER BY created_at DESC LIMIT 12')->fetchAll();
?><!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Wishlist</title><?php echo <<<'CSS'
<style>
body{margin:0;background:#f8fafc;color:#0f172a;font-family:Inter,Arial,sans-serif}.wrap{max-width:1180px;margin:auto;padding:24px}.hero{background:linear-gradient(135deg,#0f172a,#1e293b);color:#fff;border-radius:28px;padding:34px;margin-bottom:22px}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:16px}.card{background:#fff;border:1px solid #e2e8f0;border-radius:22px;padding:18px;box-shadow:0 12px 28px rgba(15,23,42,.06)}.btn{display:inline-block;border:0;border-radius:14px;background:#0f172a;color:#fff;padding:11px 14px;text-decoration:none;cursor:pointer}.btn2{background:#fff;color:#0f172a;border:1px solid #cbd5e1}.input{width:100%;box-sizing:border-box;border:1px solid #cbd5e1;border-radius:14px;padding:11px;margin-bottom:10px}.muted{color:#64748b}.price{font-size:22px;font-weight:800}.table{width:100%;border-collapse:collapse}.table td,.table th{padding:12px;border-bottom:1px solid #e2e8f0;text-align:left}@media(max-width:700px){.wrap{padding:14px}.hero{padding:24px}.grid{grid-template-columns:1fr}.table{font-size:13px}}</style>
CSS; ?></head><body><div class="wrap"><div class="hero"><h1>Wishlist</h1><p>Save products for later and convert them into quote or order discussions.</p></div><div class="grid"><div class="card" style="grid-column:span 2"><h2>Your saved products</h2><table class="table"><tr><th>Product</th><th>Qty</th><th>Price</th><th>Stock</th></tr><?php foreach($items as $i): ?><tr><td><strong><?php echo esc($i['name']); ?></strong><br><span class="muted"><?php echo esc($i['sku']); ?></span></td><td><?php echo esc($i['quantity']); ?></td><td><?php echo money($i['price']); ?></td><td><?php echo (int)$i['stock']; ?></td></tr><?php endforeach; ?><?php if(!$items): ?><tr><td colspan="4" class="muted">No wishlist products yet.</td></tr><?php endif; ?></table></div><div class="card"><h2>Add products</h2><?php foreach($products as $p): ?><p><strong><?php echo esc($p['name']); ?></strong><br><span class="muted"><?php echo money($p['price']); ?></span><br><a class="btn btn2" href="?add=<?php echo (int)$p['id']; ?>">Add</a></p><?php endforeach; ?></div></div></div></body></html>